INSERT INTO public.training_guides (category, title, steps, difficulty) VALUES
('basic', '앉아 (Sit)', '[{"step":1,"title":"간식 준비","description":"강아지가 좋아하는 간식을 손에 쥐고 강아지의 주의를 끕니다."},{"step":2,"title":"유도","description":"간식을 강아지 코 앞에 가져간 뒤 천천히 머리 위로 올립니다. 강아지는 자연스럽게 엉덩이를 내립니다."},{"step":3,"title":"명령어 연결","description":"엉덩이가 바닥에 완전히 닿는 순간 마커 신호를 외친 뒤 즉시 간식을 줍니다. 동작이 반복되어 익숙해지면 유도 시작 전에 앉아라고 명령어를 붙입니다."},{"step":4,"title":"반복 연습","description":"하루 5~10분씩 반복합니다. 성공할 때마다 칭찬과 간식을 아끼지 마세요."},{"step":5,"title":"간식 줄이기","description":"익숙해지면 간식 없이 손동작만으로 명령을 수행할 수 있도록 점차 간식을 줄여갑니다."}]', 'easy'),
('basic', '기다려 (Stay)', '[{"step":1,"title":"앉아 자세에서 시작","description":"먼저 앉아 명령을 수행시킨 후 시작합니다."},{"step":2,"title":"손바닥 신호","description":"손바닥을 강아지 코 앞에 펼치며 기다려라고 말합니다."},{"step":3,"title":"짧은 시간부터","description":"처음에는 1~2초만 기다리게 하고 즉시 칭찬합니다. 성공하면 점차 시간을 늘립니다."},{"step":4,"title":"거리 늘리기","description":"시간이 충분히 익숙해진 후에 거리를 늘립니다. 거리를 늘리는 주에는 시간을 다시 짧게 줄여 시작하세요."},{"step":5,"title":"방해물 환경 적응","description":"시간과 거리가 익숙해지면 초인종, 방문객, 야외 소음 등 방해물이 있는 환경에서도 연습합니다. 해제 명령어를 정해두고 반드시 해제 신호 후에만 자리를 이동하도록 가르칩니다."}]', 'easy'),
('basic', '이리 와 (Come)', '[{"step":1,"title":"짧은 거리에서 시작","description":"강아지와 1~2m 거리에서 쪼그려 앉아 두 팔을 벌리고 와 또는 이리 와라고 부릅니다."},{"step":2,"title":"즉시 보상","description":"강아지가 다가오는 순간 큰 칭찬과 간식으로 보상합니다. 올 때마다 항상 좋은 일이 생긴다는 것을 기억시킵니다."},{"step":3,"title":"절대 혼내지 않기","description":"와 명령으로 부른 뒤 혼내면 다음에는 오지 않습니다. 부른 후에는 반드시 칭찬만 합니다."},{"step":4,"title":"거리 늘리기","description":"성공률이 높아지면 점차 거리를 늘리고, 야외에서도 연습합니다."},{"step":5,"title":"긴 줄 연습","description":"야외에서는 5~10m 롱리드줄을 사용해 안전하게 연습합니다."}]', 'easy'),
('basic', '엎드려 (Down)', '[{"step":1,"title":"앉아 자세에서 시작","description":"앉아 명령을 수행시킨 후 시작합니다."},{"step":2,"title":"간식으로 유도","description":"간식을 강아지 코 앞에서 바닥 방향으로 천천히 내립니다. 강아지가 간식을 따라 앞발을 뻗으며 엎드리게 됩니다."},{"step":3,"title":"명령어 연결","description":"강아지가 완전히 엎드린 순간 엎드려라고 말하고 즉시 간식을 줍니다."},{"step":4,"title":"반복 연습","description":"하루 여러 번 짧게 반복하며 익힙니다."},{"step":5,"title":"다양한 장소에서 연습","description":"집 안 여러 장소와 야외에서도 연습해 어디서나 명령을 수행하도록 일반화합니다."}]', 'easy'),
('basic', '손 (Shake)', '[{"step":1,"title":"앉아 자세에서 시작","description":"앉아 명령을 수행시킨 후 시작합니다."},{"step":2,"title":"발 들어올리기 유도","description":"손에 간식을 쥐고 강아지 앞발 높이에서 주먹을 내밀면, 강아지가 간식을 꺼내려고 발로 긁습니다."},{"step":3,"title":"명령어 연결","description":"강아지 발이 손에 닿는 순간 손이라고 말하며 손을 살짝 잡아주고 간식을 줍니다."},{"step":4,"title":"악수 동작 완성","description":"점차 강아지가 발을 내밀면 자연스럽게 잡아주고 칭찬합니다."},{"step":5,"title":"반대 발 연습","description":"한쪽 발이 익숙해지면 다른 손이라는 명령으로 반대 발도 연습합니다."}]', 'easy'),
('behavior', '짖음 교정', '[{"step":1,"title":"짖는 원인 파악","description":"경계 짖음, 요구 짖음, 불안 짖음 등 원인을 먼저 파악합니다. 원인에 따라 접근법이 달라집니다."},{"step":2,"title":"짖을 때 반응하지 않기","description":"요구 짖음의 경우 짖는 동안에는 절대 반응하지 않습니다. 관심을 주거나 간식을 주면 짖음이 강화됩니다."},{"step":3,"title":"조용할 때 칭찬","description":"짖다가 잠깐 멈추는 순간을 포착해 즉시 보상합니다. 조용히 명령어는 짖음이 발생하기 전 상황에서 별도로 조건화해야 합니다."},{"step":4,"title":"자극에 둔감화","description":"경계 짖음은 자극(초인종, 방문자 등)에 반복 노출하며 긍정적 경험을 연결시킵니다."},{"step":5,"title":"일관성 유지","description":"가족 모두가 같은 방식으로 대응해야 합니다. 한 명이라도 짖을 때 반응하면 교정이 어려워집니다."}]', 'medium'),
('behavior', '물기 교정 (입 단속)', '[{"step":1,"title":"퍼피 바이팅 이해","description":"이 훈련은 퍼피 놀이 물기를 대상으로 합니다. 성견의 공격적 물기는 전문 행동 교정가 상담이 필요합니다. 생후 3~6개월은 치아 교체기로 물기 욕구가 강하므로 치발기를 충분히 제공하는 것이 핵심입니다."},{"step":2,"title":"차분한 반응 후 놀이 중단","description":"이빨이 닿는 순간 낮고 차분한 목소리로 그만이라고 말하고 즉시 놀이를 중단합니다. 흥분이 가라앉지 않으면 30~60초 자리를 피하는 타임아웃 방식을 사용하세요."},{"step":3,"title":"자리 피하기","description":"물었을 때 등을 돌리거나 자리를 피해 관심을 끊습니다. 물면 재미있는 일이 끝난다는 것을 학습시킵니다."},{"step":4,"title":"장난감으로 대체","description":"물고 싶어하면 장난감을 제공합니다. 사람 손 대신 장난감을 무는 습관을 들입니다."},{"step":5,"title":"일관성","description":"어릴 때부터 일관되게 교육합니다. 귀여워서 허용하면 성견이 되어도 무는 행동이 지속됩니다."}]', 'medium'),
('behavior', '혼자 있기 연습 (분리불안 예방)', '[{"step":1,"title":"혼자 있는 시간에 익숙하게","description":"처음에는 1~2분만 자리를 비우고 돌아옵니다. 강아지가 혼자 있어도 보호자가 돌아온다는 것을 반복 학습시킵니다."},{"step":2,"title":"출발·귀가 시 무덤덤하게","description":"외출 전후에 과도한 인사를 삼갑니다. 이별과 만남이 평범한 일임을 인식시킵니다."},{"step":3,"title":"혼자 있을 공간 마련","description":"켄넬이나 지정 공간을 안전하고 편안한 공간으로 인식하도록 평소에도 자주 이용합니다."},{"step":4,"title":"시간 점진적 늘리기","description":"성공하면 5분, 15분, 30분, 1시간 순으로 점차 늘립니다."},{"step":5,"title":"충분한 운동 제공","description":"외출 전 산책이나 놀이로 에너지를 충분히 발산시키면 혼자 있는 시간에 더 차분해집니다. 이미 분리불안이 발병한 경우에는 수의사 또는 전문 행동 교정가와 상담 후 약물 치료와 병행해야 할 수 있습니다."}]', 'medium'),
('behavior', '자원 지키기 교정', '[{"step":1,"title":"행동 심각도 파악 및 안전 확보","description":"자원 지키기는 경증(몸을 낮추거나 눈을 치켜뜨는 것)부터 중증(으르렁거림, 실제로 무는 것)까지 단계가 다릅니다. 실제로 무는 행동이 반복되거나 어린이·노약자가 있는 가정이라면 전문 행동 교정가에게 먼저 상담하세요."},{"step":2,"title":"낮은 가치 물건으로 역조건화 시작","description":"강아지가 특별히 집착하지 않는 낮은 가치의 물건으로 시작합니다. 2~3m 거리에서 고가치 간식을 강아지 쪽으로 던져주세요. 물건을 빼앗으려 하지 말고 보호자가 가까이 오면 맛있는 것이 생긴다는 긍정적 연결만 만드는 것이 목표입니다."},{"step":3,"title":"접근 거리 줄이기 반복","description":"강아지가 긴장하지 않고 간식을 먹는 것이 확인되면 조금씩 거리를 좁히며 같은 방식으로 간식을 던져줍니다. 으르렁거리거나 몸이 경직되면 즉시 한 발 물러나 이전 단계로 돌아가세요."},{"step":4,"title":"트레이드(교환) 게임","description":"강아지에게 줘 또는 트레이드라고 말하며 고가치 간식을 코 앞에 내밀어 물건을 자발적으로 놓게 유도합니다. 물건을 내려놓는 순간 즉시 간식을 주고, 잠시 후 물건을 반드시 다시 돌려줍니다."},{"step":5,"title":"밥그릇 및 고가치 자원으로 일반화","description":"낮은 가치 물건에서 성공했다면 밥그릇 등 고가치 자원으로 확장합니다. 식사 중 접근해 밥그릇에 추가 간식을 얹어 주면 보호자가 다가오면 밥이 더 생긴다는 경험이 쌓입니다. 진전이 더디거나 공격성이 지속될 경우 반드시 전문 행동 교정가와 상담하세요."}]', 'medium'),
('behavior', '낯선 자극 공포 반응 교정', '[{"step":1,"title":"공포 반응 목록 작성 및 역치 파악","description":"강아지가 어떤 자극(천둥, 청소기, 낯선 사람 등)에 어떤 반응을 보이는지 기록합니다. 간식을 전혀 받지 않을 정도로 패닉 상태라면 이미 역치를 초과한 것이므로 즉시 강도를 낮추거나 수의사 상담을 먼저 받으세요."},{"step":2,"title":"아주 약한 강도의 자극으로 역조건화 시작","description":"소리 자극이라면 아주 낮은 볼륨으로 재생하고, 낯선 사람이라면 멀리 보이는 거리에서 시작합니다. 자극이 발생하는 순간 즉시 고가치 간식을 주어 이 자극이 나타나면 맛있는 것이 온다는 긍정적 연결을 만듭니다."},{"step":3,"title":"아주 천천히 자극 강도 높이기","description":"강아지가 현재 강도에서 긴장 없이 간식을 먹고 편안한 상태를 보이면 강도를 아주 조금씩 높여 나갑니다. 으르렁거림, 떨림, 도망치려는 행동이 보이면 훈련 속도가 너무 빠른 것이므로 이전 단계로 돌아가세요."},{"step":4,"title":"안정 행동과 연결하여 훈련","description":"공포 반응이 줄어들기 시작하면 자극이 나타날 때 앉아 또는 엎드려를 요청하고 수행 시 간식을 줍니다. 특정 행동을 요청하면 강아지는 무엇을 해야 할지 알게 되어 더 안정적인 상태를 유지할 수 있습니다."},{"step":5,"title":"다양한 환경에서 일반화 및 유지","description":"실내에서 성공했다면 소음이 실제로 발생하는 환경으로 점차 확장합니다. 수 주 이상 진행해도 공황에 가까운 반응이 지속된다면 수의사 또는 전문 동물행동 교정가에게 상담받으세요."}]', 'medium'),
('trick', '빙글빙글 돌기 (Spin)', '[{"step":1,"title":"기초 훈련 선행","description":"앉아, 기다려 등 기초 훈련이 되어 있어야 합니다."},{"step":2,"title":"간식으로 유도","description":"간식을 강아지 코 앞에 대고 원을 그리듯 천천히 이동시킵니다. 강아지가 간식을 따라 몸을 돌립니다."},{"step":3,"title":"한 바퀴 완성","description":"처음에는 반 바퀴, 다음에는 한 바퀴 완전히 돌 때 간식을 줍니다."},{"step":4,"title":"명령어 연결","description":"동작이 익숙해지면 돌기 시작할 때 돌아 또는 스핀이라고 말합니다."},{"step":5,"title":"양방향 연습","description":"한 방향이 익숙해지면 반대 방향도 연습합니다. 뇌 자극에도 좋습니다."}]', 'medium'),
('trick', '죽은 척 (Bang)', '[{"step":1,"title":"엎드려 자세에서 시작","description":"엎드려 명령을 수행시킨 후 시작합니다."},{"step":2,"title":"옆으로 눕히기","description":"간식을 강아지 코에서 어깨 뒤쪽으로 천천히 이동시키면 강아지가 몸을 돌려 옆으로 눕습니다."},{"step":3,"title":"정지 자세 유지","description":"완전히 누운 상태에서 2~3초 유지하면 간식을 줍니다. 점차 유지 시간을 늘립니다."},{"step":4,"title":"명령어 연결","description":"손가락 총 모양을 만들며 뱅이라고 말하고 동작을 유도합니다."},{"step":5,"title":"손동작만으로 수행","description":"익숙해지면 간식 없이 손동작과 명령어만으로 수행할 수 있도록 연습합니다."}]', 'hard'),
('trick', '하이파이브 (High Five)', '[{"step":1,"title":"손 명령 선행","description":"손(악수) 훈련이 되어 있으면 더 쉽게 배울 수 있습니다. 손 훈련이 안 된 경우 먼저 완료한 뒤 시작하세요."},{"step":2,"title":"높이 올리기","description":"간식을 손에 쥐고 강아지 가슴 높이보다 위로 주먹을 들어올립니다. 강아지가 간식을 꺼내려고 평소보다 발을 더 높이 들게 됩니다."},{"step":3,"title":"손바닥에 닿으면 보상","description":"주먹 대신 손바닥을 펼쳐 내밀고, 강아지 발바닥이 손바닥에 닿는 순간 즉시 마커 신호와 함께 간식을 줍니다."},{"step":4,"title":"명령어 연결","description":"동작이 안정적으로 완성되면 손을 내미는 동시에 하이파이브라고 말합니다."},{"step":5,"title":"양발 연습","description":"한쪽 발이 익숙해지면 반대 손을 내밀며 반대 발도 연습합니다. 두 발을 구분하려면 명령어를 다르게 설정하는 것이 좋습니다."}]', 'medium');
